import{_ as l,c as a,l as e,a as i,t,a4 as d,o as r}from"./chunks/framework.CzsDe1xi.js";const k=JSON.parse('{"title":"Pod详解","description":"","frontmatter":{"title":"Pod详解"},"headers":[],"relativePath":"doc/DevOps/Kubernetes/基础/Pod/pod.md","filePath":"packages/doc/src/DevOps/Kubernetes/基础/Pod/pod.md","lastUpdated":1705159462000}'),p={name:"doc/DevOps/Kubernetes/基础/Pod/pod.md"},n={id:"frontmatter-title",tabindex:"-1"},s=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),c=d('<h2 id="什么是pod" tabindex="-1">什么是pod? <a class="header-anchor" href="#什么是pod" aria-label="Permalink to &quot;什么是pod?&quot;">​</a></h2><p>运行中的一组容器，Pod是kubernetes中应用的最小单位.</p><h2 id="pod的组成" tabindex="-1">pod的组成 <a class="header-anchor" href="#pod的组成" aria-label="Permalink to &quot;pod的组成&quot;">​</a></h2><p>一个pod中可以包含多个容器，这些容器共享网络和存储</p><h2 id="pod的特性" tabindex="-1">pod的特性 <a class="header-anchor" href="#pod的特性" aria-label="Permalink to &quot;pod的特性&quot;">​</a></h2><ul><li>原子性: 一个pod中的容器是作为一个整体运行，一个pod中的容器不能单独运行.</li><li>共享资源: 一个pod中的容器可以共享网络和存储.</li><li>生命周期: 一个pod的生命周期是和它的所有容器一起的.</li><li>共享网络和存储: 一个pod中的容器共享网络和存储.</li><li>调度: 一个pod可以调度到一个节点上运行.</li><li>协同: 一个pod中的容器可以协同工作.</li></ul><h2 id="pod的创建方式" tabindex="-1">pod的创建方式 <a class="header-anchor" href="#pod的创建方式" aria-label="Permalink to &quot;pod的创建方式&quot;">​</a></h2><ul><li>手动创建: 使用yaml文件创建pod.</li><li>控制器创建: 使用控制器创建pod.</li><li>命令行创建: 使用kubectl命令行创建pod.</li><li>创建模板: 使用pod模板创建pod.</li><li>创建控制器: 使用控制器创建pod.</li><li>创建Deployment: 使用Deployment创建pod.</li><li>创建DaemonSet: 使用DaemonSet创建pod.</li><li>创建StatefulSet: 使用StatefulSet创建pod.</li><li>创建Job: 使用Job创建pod.</li><li>创建CronJob: 使用CronJob创建pod.</li><li>创建ReplicaSet: 使用ReplicaSet创建pod.</li><li>创建ReplicationController: 使用ReplicationController创建pod.</li></ul><h2 id="pod-常见的状态" tabindex="-1">Pod 常见的状态 <a class="header-anchor" href="#pod-常见的状态" aria-label="Permalink to &quot;Pod 常见的状态&quot;">​</a></h2><ul><li>Pending：挂起，我们在请求创建 pod 时，条件不满足，调度没有完成，没有任何一个节点能满足调度条件。已经创建了但是没有适合它运行的节点叫做挂起，这其中也包含集群为容器创建网络，或者下载镜像的过程。</li><li>Running：Pod 内所有的容器都已经被创建，且至少一个容器正在处于运行状态、正在启动状态或者重启状态。</li><li>Succeeded：Pod 中所以容器都执行成功后退出，并且没有处于重启的容器。</li><li>Failed：Pod 中所以容器都已退出，但是至少还有一个容器退出时为失败状态。</li><li>Unknown：未知状态，所谓 pod 是什么状态是 apiserver 和运行在 pod 节点的 kubelet 进行通信获取状态信息的，如果节点之上的 kubelet 本身出故障，那么 apiserver 就连不上 kubelet，得不到信息了，就会看 Unknown</li></ul><h2 id="pod-重启策略" tabindex="-1">Pod 重启策略 <a class="header-anchor" href="#pod-重启策略" aria-label="Permalink to &quot;Pod 重启策略&quot;">​</a></h2><ul><li>Always: 只要容器失效退出就重新启动容器。</li><li>OnFailure: 当容器以非正常(异常)退出后才自动重新启动容器。</li><li>Never: 无论容器状态如何，都不重新启动容器。</li></ul>',12);function h(o,u,_,b,m,P){return r(),a("div",null,[e("h1",n,[i(t(o.$frontmatter.title)+" ",1),s]),c])}const S=l(p,[["render",h]]);export{k as __pageData,S as default};
